member.example:
Bind the TMP_Text font using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextFontBinder _font;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_FontAsset _font;
    }


Bind the TMP_Text font by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextFontBinder Font =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_FontAsset _font;
    }

Switch the TMP_Text font between two values using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextFontSwitcherBinder _isBold;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isBold;
    }


Switch the TMP_Text font between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private TMP_Text _target;
        
        [SerializeField] 
        private TMP_FontAsset _boldFont;
        
        [SerializeField] 
        private TMP_FontAsset _regularFont;
        
        private TextFontSwitcherBinder IsBold => new(
            _target, _boldFont, _regularFont);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isBold;
    }
